import html from "./index.html";

const ICON192 = "";
const ICON512 = "";
const FAVICON = "";

const MANIFEST = JSON.stringify({
  name: "Asturiano — Sistema de Reclamos",
  short_name: "Asturiano",
  description: "Sistema de gestión de reclamos del Centro Asturiano de Buenos Aires",
  start_url: "/",
  display: "standalone",
  background_color: "#0f172a",
  theme_color: "#0f172a",
  orientation: "portrait-primary",
  icons: [
    { src: "/icon-192.png", sizes: "192x192", type: "image/png", purpose: "any maskable" },
    { src: "/icon-512.png", sizes: "512x512", type: "image/png", purpose: "any maskable" }
  ]
});

const SW = `const CACHE="asturiano-v2";self.addEventListener("install",e=>{self.skipWaiting();});self.addEventListener("activate",e=>{e.waitUntil(caches.keys().then(keys=>Promise.all(keys.filter(k=>k!==CACHE).map(k=>caches.delete(k)))));} );self.addEventListener("fetch",e=>{if(e.request.method!=="GET")return;e.respondWith(fetch(e.request).then(res=>{const clone=res.clone();caches.open(CACHE).then(c=>c.put(e.request,clone));return res;}).catch(()=>caches.match(e.request)));} );`;

function b64ToBytes(b64) {
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes;
}

function injectPWA(htmlStr) {
  const pwaHead = `
  <link rel="manifest" href="/manifest.json">
  <link rel="icon" href="/favicon.ico" type="image/x-icon">
  <meta name="theme-color" content="#0f172a">
  <meta name="apple-mobile-web-app-capable" content="yes">
  <meta name="apple-mobile-web-app-status-bar-style" content="black-translucent">
  <meta name="apple-mobile-web-app-title" content="Asturiano">
  <link rel="apple-touch-icon" href="/icon-192.png">
  <script>if("serviceWorker"in navigator)window.addEventListener("load",()=>navigator.serviceWorker.register("/sw.js"));<\/script>`;
  return htmlStr.replace("</head>", pwaHead + "\n</head>");
}

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (path === "/manifest.json")
      return new Response(MANIFEST, {
        headers: { "Content-Type": "application/manifest+json", "Cache-Control": "public, max-age=86400" }
      });

    if (path === "/sw.js")
      return new Response(SW, {
        headers: { "Content-Type": "application/javascript", "Cache-Control": "no-cache" }
      });

    if (path === "/icon-192.png")
      return new Response(b64ToBytes(ICON192), {
        headers: { "Content-Type": "image/png", "Cache-Control": "public, max-age=604800" }
      });

    if (path === "/icon-512.png")
      return new Response(b64ToBytes(ICON512), {
        headers: { "Content-Type": "image/png", "Cache-Control": "public, max-age=604800" }
      });

    if (path === "/favicon.ico")
      return new Response(b64ToBytes(FAVICON), {
        headers: { "Content-Type": "image/x-icon", "Cache-Control": "public, max-age=604800" }
      });

    return new Response(injectPWA(html), {
      headers: { "Content-Type": "text/html;charset=UTF-8" },
    });
  },
};
